public class StudentView { public void displayStudentDetails(String studentId, String studentName, String grade) { System.out.println("+==========================+"); System.out.println("|    Student Information    |"); System.out.println("+==========================+"); System.out.printf("|  ID    : %-16s |%n", studentId); System.out.printf("|  Name  : %-16s |%n", studentName); System.out.printf("|  Grade : %-16s |%n", grade); System.out.println("+==========================+"); } }